   171→	private getAllModeIds(descriptions: LanguageDescription[], pluginManager: PluginManager) {
   172→		return [
   173→			...descriptions.map(x => x.languageIds),
   174→			...pluginManager.plugins.map(x => x.languages)
   175→		].flat();
