   261→class GetErrRequest {
   262→
   263→	public static executeGetErrRequest(
   264→		client: ITypeScriptServiceClient,
   265→		files: ResourceMap<void | vscode.Range[]>,
   266→		onDone: () => void
   267→	) {
   268→		return new GetErrRequest(client, files, onDone);
   269→	}
   270→
   271→	private _done: boolean = false;
   272→	private readonly _token: vscode.CancellationTokenSource = new vscode.CancellationTokenSource();
   273→
   274→	private constructor(
   275→		private readonly client: ITypeScriptServiceClient,
   276→		public readonly files: ResourceMap<void | vscode.Range[]>,
   277→		onDone: () => void
   278→	) {
   279→		if (!this.isErrorReportingEnabled()) {
   280→			this._done = true;
   281→			setImmediate(onDone);
   282→			return;
   283→		}
   284→
   285→		const supportsSyntaxGetErr = this.client.apiVersion.gte(API.v440);
   286→		const fileEntries = Array.from(files.entries()).filter(entry => supportsSyntaxGetErr || client.hasCapabilityForResource(entry.resource, ClientCapability.Semantic));
   287→		const allFiles = coalesce(fileEntries
   288→			.map(entry => client.toTsFilePath(entry.resource)));
   289→
   290→		if (!allFiles.length) {
   291→			this._done = true;
   292→			setImmediate(onDone);
   293→		} else {
   294→			let request;
   295→			if (this.areProjectDiagnosticsEnabled()) {
   296→				// Note that geterrForProject is almost certainly not the api we want here as it ends up computing far
   297→				// too many diagnostics
   298→				request = client.executeAsync('geterrForProject', { delay: 0, file: allFiles[0] }, this._token.token);
   299→			}
   300→			else {
   301→				let requestFiles;
   302→				if (this.areRegionDiagnosticsEnabled()) {
   303→					requestFiles = coalesce(fileEntries
   304→						.map(entry => {
   305→							const file = client.toTsFilePath(entry.resource);
   306→							const ranges = entry.value;
   307→							if (file && ranges) {
   308→								return typeConverters.Range.toFileRangesRequestArgs(file, ranges);
   309→							}
   310→
   311→							return file;
   312→						}));
   313→				}
   314→				else {
   315→					requestFiles = allFiles;
   316→				}
   317→				request = client.executeAsync('geterr', { delay: 0, files: requestFiles }, this._token.token);
   318→			}
   319→
   320→			request.finally(() => {
   321→				if (this._done) {
   322→					return;
   323→				}
   324→				this._done = true;
   325→				onDone();
   326→			});
   327→		}
   328→	}
   329→
   330→	private isErrorReportingEnabled() {
   331→		if (this.client.apiVersion.gte(API.v440)) {
   332→			return true;
   333→		} else {
   334→			// Older TS versions only support `getErr` on semantic server
   335→			return this.client.capabilities.has(ClientCapability.Semantic);
   336→		}
   337→	}
   338→
   339→	private areProjectDiagnosticsEnabled() {
   340→		return this.client.configuration.enableProjectDiagnostics && this.client.capabilities.has(ClientCapability.Semantic);
   341→	}
   342→
   343→	private areRegionDiagnosticsEnabled() {
   344→		return this.client.configuration.enableRegionDiagnostics && this.client.apiVersion.gte(API.v560);
   345→	}
   346→
   347→	public cancel(): any {
   348→		if (!this._done) {
   349→			this._token.cancel();
   350→		}
   351→
   352→		this._token.dispose();
   353→	}
   354→}
