   356→class TabResourceTracker extends Disposable {
   357→
   358→	private readonly _onDidChange = this._register(new vscode.EventEmitter<{
   359→		readonly closed: Iterable<vscode.Uri>;
   360→		readonly opened: Iterable<vscode.Uri>;
   361→	}>());
   362→	public readonly onDidChange = this._onDidChange.event;
   363→
   364→	private readonly _tabResources: ResourceMap<{ readonly tabs: Set<vscode.Tab> }>;
   365→
   366→	constructor(
   367→		normalizePath: (resource: vscode.Uri) => string | undefined,
   368→		config: {
   369→			readonly onCaseInsensitiveFileSystem: boolean;
   370→		},
   371→	) {
   372→		super();
   373→
   374→		this._tabResources = new ResourceMap<{ readonly tabs: Set<vscode.Tab> }>(normalizePath, config);
   375→
   376→		for (const tabGroup of vscode.window.tabGroups.all) {
   377→			for (const tab of tabGroup.tabs) {
   378→				this.add(tab);
   379→			}
   380→		}
   381→
   382→		this._register(vscode.window.tabGroups.onDidChangeTabs(e => {
   383→			const closed = e.closed.flatMap(tab => this.delete(tab));
   384→			const opened = e.opened.flatMap(tab => this.add(tab));
   385→			if (closed.length || opened.length) {
   386→				this._onDidChange.fire({ closed, opened });
   387→			}
   388→		}));
   389→	}
   390→
   391→	public has(resource: vscode.Uri): boolean {
   392→		if (resource.scheme === fileSchemes.vscodeNotebookCell) {
   393→			const notebook = vscode.workspace.notebookDocuments.find(doc =>
   394→				doc.getCells().some(cell => cell.document.uri.toString() === resource.toString()));
   395→
   396→			return !!notebook && this.has(notebook.uri);
   397→		}
   398→
   399→		const entry = this._tabResources.get(resource);
   400→		return !!entry && entry.tabs.size > 0;
   401→	}
   402→
   403→	private add(tab: vscode.Tab): vscode.Uri[] {
   404→		const addedResources: vscode.Uri[] = [];
   405→		for (const uri of this.getResourcesForTab(tab)) {
   406→			const entry = this._tabResources.get(uri);
   407→			if (entry) {
   408→				entry.tabs.add(tab);
   409→			} else {
   410→				this._tabResources.set(uri, { tabs: new Set([tab]) });
   411→				addedResources.push(uri);
   412→			}
   413→		}
   414→		return addedResources;
   415→	}
   416→
   417→	private delete(tab: vscode.Tab): vscode.Uri[] {
   418→		const closedResources: vscode.Uri[] = [];
   419→		for (const uri of this.getResourcesForTab(tab)) {
   420→			const entry = this._tabResources.get(uri);
   421→			if (!entry) {
   422→				continue;
   423→			}
   424→
   425→			entry.tabs.delete(tab);
   426→			if (entry.tabs.size === 0) {
   427→				this._tabResources.delete(uri);
   428→				closedResources.push(uri);
   429→			}
   430→		}
   431→		return closedResources;
   432→	}
   433→
   434→	private getResourcesForTab(tab: vscode.Tab): vscode.Uri[] {
   435→		if (tab.input instanceof vscode.TabInputText) {
   436→			return [tab.input.uri];
   437→		} else if (tab.input instanceof vscode.TabInputTextDiff) {
   438→			return [tab.input.original, tab.input.modified];
   439→		} else if (tab.input instanceof vscode.TabInputNotebook) {
   440→			return [tab.input.uri];
   441→		} else {
   442→			return [];
   443→		}
   444→	}
   445→}
