import * as assert from 'assert';
import 'mocha';
import * as vscode from 'vscode';
import * as fs from 'fs';
import * as path from 'path';
import { wait } from '../../test/testUtils';
import { disposeAll } from '../../utils/dispose';

suite('TypeScript Stale Diagnostics', () => {

	const _disposables: vscode.Disposable[] = [];
	let testDir: string;

	setup(async () => {
		// the tests assume that typescript features are registered
		await vscode.extensions.getExtension('vscode.typescript-language-features')!.activate();

		// Create a temporary test directory
		testDir = path.join(__dirname, '../../../../.test-stale-diag');
		if (!fs.existsSync(testDir)) {
			fs.mkdirSync(testDir, { recursive: true });
		}
	});

	teardown(async () => {
		disposeAll(_disposables);
		await vscode.commands.executeCommand('workbench.action.closeAllEditors');

		// Clean up test directory
		if (fs.existsSync(testDir)) {
			fs.rmSync(testDir, { recursive: true, force: true });
		}
	});

	test('Diagnostics should update when file changes on disk', async () => {
		const testFile = path.join(testDir, 'test.ts');

		// Create a file with an error
		const originalContent = `const x: string = 123;`;
		fs.writeFileSync(testFile, originalContent);

		// Open the file in the editor
		const doc = await vscode.workspace.openTextDocument(testFile);
		await vscode.window.showTextDocument(doc);
		_disposables.push({ dispose: () => { /* no-op */ } });

		// Wait for diagnostics to be computed
		await wait(2000);

		// Get initial diagnostics
		const initialDiagnostics = vscode.languages.getDiagnostics(doc.uri);
		assert.ok(initialDiagnostics.length > 0, 'Should have diagnostics for type error');

		// Simulate a git branch switch by changing file on disk to valid code
		const validContent = `const x: string = "hello";`;
		fs.writeFileSync(testFile, validContent);

		// Wait for file system watcher to detect the change and request diagnostics
		await wait(2000);

		// Get new diagnostics
		const newDiagnostics = vscode.languages.getDiagnostics(doc.uri);

		// The diagnostics should be updated (fewer errors)
		assert.ok(newDiagnostics.length < initialDiagnostics.length,
			'Diagnostics should update when file changes on disk');
	});

	test('Diagnostics should clear when file has no errors after disk change', async () => {
		const testFile = path.join(testDir, 'test-no-errors.ts');

		// Create a file with an error
		const errorContent = `const x: string = 123;`;
		fs.writeFileSync(testFile, errorContent);

		// Open the file
		const doc = await vscode.workspace.openTextDocument(testFile);
		await vscode.window.showTextDocument(doc);
		_disposables.push({ dispose: () => { /* no-op */ } });

		// Wait for diagnostics
		await wait(2000);

		// Get initial diagnostics (should have errors)
		const initialDiagnostics = vscode.languages.getDiagnostics(doc.uri);
		const initialErrorCount = initialDiagnostics.length;
		assert.ok(initialErrorCount > 0, 'Should have diagnostics initially');

		// Change file on disk to have no errors
		const validContent = `const x: string = "valid";`;
		fs.writeFileSync(testFile, validContent);

		// Wait for file system watcher and diagnostics
		await wait(2000);

		// Get new diagnostics
		const newDiagnostics = vscode.languages.getDiagnostics(doc.uri);

		// Diagnostics should be cleared or reduced
		assert.ok(newDiagnostics.length === 0 || newDiagnostics.length < initialErrorCount,
			'Diagnostics should clear when file has no errors');
	});
});

